+        <ContributionSuggestions contributions={contributions} />
+
+        {/* Analysis Timeline */}
+        <AnalysisTimeline steps={analysisSteps} />
+      </div>
+
+      {/* Quick Actions Panel */}
+      <QuickActionsPanel />
+    </div>
+  );
+}
