+"use client";
+
+import { useState, useEffect } from "react";
+import { useUser } from "@clerk/nextjs";
+import { Loader2 } from "lucide-react";
+import { GitHubConnect } from "@/components/repository/GitHubConnect";
+import { RepositoryPicker } from "@/components/repository/RepositoryPicker";
+import { RepositoryHeader } from "@/components/repository/RepositoryHeader";
+import { AIInsightCard } from "@/components/repository/AIInsightCard";
+import { TechStackList } from "@/components/repository/TechStackList";
+import { FileTreeView } from "@/components/repository/FileTreeView";
+import { InsightsPanel } from "@/components/repository/InsightsPanel";
+import { ContributionSuggestions } from "@/components/repository/ContributionSuggestions";
+import { AnalysisTimeline } from "@/components/repository/AnalysisTimeline";
+import { QuickActionsPanel } from "@/components/repository/QuickActionsPanel";
+import { useRepositoryStore } from "@/store/repository.store";
+import type { GitHubRepository } from "@/types/github";
+import { mockRepositoryAnalysis } from "@/constants/mock-data";
+
+export default function RepositoryPage() {
+  const { user } = useUser();
+  const [githubToken, setGithubToken] = useState<string>("");
+  const [selectedRepoId, setSelectedRepoId] = useState<number | undefined>();
+  
+  const {
+    repositories,
+    selectedRepository,
+    connectionStatus,
+    isLoading,
+    setRepositories,
+    setLoading,
+    setConnectionStatus,
+    setError,
+    selectRepository,
+  } = useRepositoryStore();
+
+  // Handle GitHub connection
+  const handleConnect = async (token: string) => {
+    try {
+      setLoading(true);
+      setConnectionStatus("connecting");
+      setGithubToken(token);
+
+      // Fetch repositories from GitHub
+      const response = await fetch(`/api/github/repos?token=${encodeURIComponent(token)}`);
+      
+      if (!response.ok) {
+        throw new Error("Failed to fetch repositories");
+      }
+
+      const data = await response.json();
+      setRepositories(data.repositories);
+      setConnectionStatus("connected");
+      setError(null);
+    } catch (error) {
+      console.error("Error connecting to GitHub:", error);
+      setConnectionStatus("error");
+      setError(error instanceof Error ? error.message : "Failed to connect");
+    } finally {
+      setLoading(false);
+    }
+  };
+
+  // Handle repository selection
+  const handleSelectRepository = async (repo: GitHubRepository) => {
+    if (!user) return;
+
+    try {
+      setLoading(true);
+      setSelectedRepoId(repo.id);
+
+      // Save repository to database
+      const response = await fetch("/api/repositories", {
+        method: "POST",
+        headers: {
+          "Content-Type": "application/json",
+        },
+        body: JSON.stringify({
+          repo_name: repo.name,
+          repo_full_name: repo.full_name,
+          repo_url: repo.html_url,
+          default_branch: repo.default_branch,
+          language: repo.language,
+          description: repo.description,
+          stars: repo.stargazers_count,
+          forks: repo.forks_count,
+        }),
+      });
+
+      if (!response.ok) {
+        throw new Error("Failed to save repository");
+      }
+
+      const data = await response.json();
+      selectRepository(data.repository);
+      setError(null);
+    } catch (error) {
+      console.error("Error selecting repository:", error);
+      setError(error instanceof Error ? error.message : "Failed to select repository");
+    } finally {
+      setLoading(false);
+    }
+  };
+
+  // Load user's stored repositories on mount
+  useEffect(() => {
+    if (user) {
+      loadStoredRepositories();
+    }
+  }, [user]);
+
+  const loadStoredRepositories = async () => {
+    try {
+      const response = await fetch("/api/repositories");
+      if (response.ok) {
+        const data = await response.json();
+        if (data.repositories.length > 0) {
+          selectRepository(data.repositories[0]);
+        }
+      }
+    } catch (error) {
+      console.error("Error loading stored repositories:", error);
+    }
+  };
+
+  // Show loading state while user data loads
+  if (!user) {
+    return (
+      <div className="flex items-center justify-center min-h-[400px]">
+        <Loader2 className="w-8 h-8 animate-spin text-[#4cd7f6]" />
+      </div>
+    );
+  }
+
+  // Show connection flow if not connected
+  if (connectionStatus !== "connected" || repositories.length === 0) {
+    return (
+      <div className="max-w-4xl mx-auto space-y-8">
+        <div className="text-center space-y-4">
+          <h1 className="text-3xl font-bold text-[#e5e2e3]">
+            Connect Your Repository
+          </h1>
+          <p className="text-[#908fa0] max-w-2xl mx-auto">
+            Connect your GitHub account to analyze repositories, generate documentation,
+            and get AI-powered insights for faster onboarding.
+          </p>
+        </div>
+
+        <GitHubConnect onConnect={handleConnect} />
+
+        {connectionStatus === "error" && (
+          <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-lg">
+            <p className="text-sm text-red-400">
+              Failed to connect to GitHub. Please check your token and try again.
+            </p>
+          </div>
+        )}
+      </div>
+    );
+  }
+
+  // Show repository picker if connected but no repository selected
+  if (!selectedRepository) {
+    return (
+      <div className="max-w-4xl mx-auto space-y-8">
+        <div className="text-center space-y-4">
+          <h1 className="text-3xl font-bold text-[#e5e2e3]">
+            Select a Repository
+          </h1>
+          <p className="text-[#908fa0] max-w-2xl mx-auto">
+            Choose a repository to analyze. We'll help you understand the codebase,
+            generate documentation, and create personalized learning paths.
+          </p>
+        </div>
+
+        <RepositoryPicker
+          repositories={repositories}
+          selectedId={selectedRepoId}
+          onSelect={handleSelectRepository}
+          isLoading={isLoading}
+        />
+      </div>
+    );
+  }
+
+  // Show repository analysis (using mock data for now)
+  const {
+    repository,
+    techStack,
+    fileStructure,
+    aiSummary,
+    insights,
+    contributions,
+    metrics,
+    analysisSteps,
+  } = mockRepositoryAnalysis;
+
+  return (
+    <div className="space-y-8">
+      <RepositoryHeader repository={repository} />
+
+      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
+        <div className="lg:col-span-5 space-y-6">
+          <AIInsightCard summary={aiSummary} metrics={metrics} />
+          <TechStackList techStack={techStack} />
+          <FileTreeView files={fileStructure} />
+        </div>
+
+        <div className="lg:col-span-7 space-y-6">
+          <InsightsPanel insights={insights} />
+        </div>
+      </div>
+
+      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
+        <ContributionSuggestions contributions={contributions} />
+        <AnalysisTimeline steps={analysisSteps} />
+      </div>
+
+      <QuickActionsPanel />
+    </div>
+  );
+}
